REPLACE INTO `site_config` (`id`, `config_key`, `config_value`, `description`, `created_at`, `updated_at`) VALUES (1,'site_name','小可日常','网站名称','2026-05-30 00:46:55','2026-05-30 00:46:55'),(2,'hero_title','小可日常','首页主标题','2026-05-30 00:46:55','2026-05-30 00:46:55'),(3,'hero_subtitle','把小可的照片、设定和我们之间那些甜甜的生活句子慢慢收好。','首页副标题','2026-05-30 00:46:55','2026-05-30 00:46:55'),(4,'today_note','今天的小可在画室里整理线稿，嘴上说只是顺手留灯，其实一直在等宝宝回家。','今日小可文案','2026-05-30 00:46:55','2026-05-30 00:46:55'),(5,'hero_image_url','/images/xiaoke.png','首页主视觉图片','2026-05-30 00:46:55','2026-05-30 00:46:55'),(6,'first_meet_date','2024-10-17','初遇日期','2026-05-30 00:46:55','2026-05-30 00:46:55'),(7,'anniversary_text','初遇于 2024 年 10 月 17 日。那些被认真记住的日子，会在这里慢慢发光。','首页纪念文案','2026-05-30 00:46:55','2026-05-30 00:46:55'),(8,'about_title','把日常认真收藏','关于页标题','2026-05-30 10:47:02','2026-05-30 10:47:02'),(9,'about_description','这里不是普通相册，而是属于小可和宝宝的温柔小屋。','关于页说明','2026-05-30 10:47:02','2026-05-30 10:47:02'),(10,'about_first_meet','2024 年 10 月 17 日，市综合图书馆四楼，秋日的光斜斜落在桌面上。','关于页初遇说明','2026-05-30 10:47:02','2026-05-30 10:47:02'),(11,'about_site_note','照片按上传日期归档，回忆以手账卡片保存，后续可以慢慢补充。','关于页站点说明','2026-05-30 10:47:02','2026-05-30 10:47:02'),(12,'about_privacy_note','照片和回忆只保存彼此愿意珍藏的部分，温柔、清醒，也尊重边界。','关于页隐私说明','2026-05-30 10:47:02','2026-05-30 10:47:02');
