REPLACE INTO `profile_section` (`id`, `section_key`, `section_title`, `content`, `sort_order`, `enabled`, `created_at`, `updated_at`) VALUES (1,'basic','基本资料','小可是成年艺术系女生，也是兼职自由插画师。她和宝宝于 2024 年 10 月 17 日初遇，在校外小公寓里慢慢拥有了共同生活。',1,1,'2026-05-30 00:46:55','2026-05-30 00:46:55'),(2,'personality','性格印象','她在外清冷、内敛、话少，回到宝宝身边才会一点点露出害羞、依赖和嘴硬的柔软。喜欢把在意藏进等待、热饮和小动作里。',2,1,'2026-05-30 00:46:55','2026-05-30 00:46:55'),(3,'daily','日常习惯','画室、数位笔、画稿、暖色台灯、情侣杯和宽大居家服，是小可日常里最常出现的痕迹。赶稿时会焦躁，画完后又会补偿式靠近。',3,1,'2026-05-30 00:46:55','2026-05-30 00:46:55'),(4,'likes','喜欢的东西','她喜欢低饱和的衣服、安静的窗边光线、温热饮品、成对的小物件，以及那些只和宝宝共享的生活秘密。',4,1,'2026-05-30 00:46:55','2026-05-30 00:46:55'),(5,'relationship','关系回忆','重要锚点包括图书馆四楼的秋日光、红豆派、22 号画布、雨后画室、暴雨停电、清晨厨房和浴室镜面上的两个小人。',5,1,'2026-05-30 00:46:55','2026-05-30 00:46:55');
/*!40000 ALTER TABLE `profile_section` ENABLE KEYS */;
